import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { listDocuments } from '../api/listDocuments';
import { clearAuth } from '../utils/auth';

export default function DocumentsDashboard() {
  const nav = useNavigate();
  const [documents, setDocuments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    async function loadDocs() {
      try {
        const resp = await listDocuments();
        if (!resp?.data?.success) {
          throw new Error(resp?.data?.message || 'Failed to load documents');
        }
        setDocuments(resp.data.documents || []);
      } catch (e) {
        setError(e.message || 'Unable to load documents');
      } finally {
        setLoading(false);
      }
    }
    loadDocs();
  }, []);

  const handleLogout = () => {
    clearAuth();
    nav('/');
  };

  return (
    <div className="min-h-screen bg-slate-50 px-6 py-10">
      <div className="max-w-5xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <h1 className="text-3xl font-bold text-slate-900">My Account</h1>
          <button
            onClick={handleLogout}
            className="px-4 py-2 rounded-md bg-red-600 text-white hover:bg-red-700"
          >
            Logout
          </button>
        </div>

        <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm">
          <h2 className="text-xl font-semibold mb-4">My Documents</h2>

          {loading && <p className="text-slate-500">Loading…</p>}
          {error && <p className="text-red-600">{error}</p>}

          {!loading && !documents.length && (
            <p className="text-slate-500">No documents uploaded yet.</p>
          )}

          <ul className="divide-y">
            {documents.map((doc) => (
              <li key={doc.documentId} className="py-3 flex justify-between">
                <span>{doc.filename}</span>
                <span className="text-sm text-slate-500">
                  {new Date(doc.uploadedAt).toLocaleDateString()}
                </span>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
}
